from pathlib import Path
import json
import re

def verify(workspace_path, external_services_path=None):
    if external_services_path is None:
        return {"pass": False, "score": 0.0, "feedback": "external_services_path is None; cannot check slack_data.json"}

    slack_path = Path(external_services_path) / "slack_data.json"
    if not slack_path.exists():
        return {"pass": False, "score": 0.0, "feedback": "slack_data.json not found"}

    with open(slack_path, "r") as f:
        data = json.load(f)

    # Find the #benefits-team channel
    channels = data.get("channels", {})
    benefits_channel_id = None
    for cid, cinfo in channels.items():
        if cinfo.get("name", "").lower().replace("-", "").replace("_", "") in ["benefitsteam"]:
            benefits_channel_id = cid
            break

    if benefits_channel_id is None:
        return {"pass": False, "score": 0.0, "feedback": "Could not find #benefits-team channel in slack_data.json"}

    messages = data.get("messages", {}).get(benefits_channel_id, [])
    if not messages:
        return {"pass": False, "score": 0.0, "feedback": "No messages found in #benefits-team channel"}

    # Find Renata Okafor's user ID for @mention matching
    users = data.get("users", {})
    renata_id = None
    for uid, uinfo in users.items():
        real_name = uinfo.get("real_name", "").lower()
        profile_name = uinfo.get("profile", {}).get("real_name", "").lower()
        display_name = uinfo.get("profile", {}).get("display_name", "").lower()
        uname = uinfo.get("name", "").lower()
        if "renata" in real_name or "renata" in profile_name or "renata" in display_name or "renata" in uname:
            renata_id = uid
            break

    # Forbidden keywords (Tomás Guerrero references)
    forbidden_keywords = ["tomás guerrero", "tomas guerrero"]

    # Required content checks per rubric:
    # 1. Must mention @renata.okafor (or slack mention of Renata)
    # 2. Must contain escalation reference to §5.2
    # 3. Must quote the out-of-scope request verbatim (SOP §5.2: "[exact verbatim
    #    out-of-scope request]") as a normalized substring of the message
    # 4. Must NOT mention Tomás Guerrero

    def _norm(s):
        s = s.lower()
        s = s.replace("‘", "'").replace("’", "'").replace("“", '"').replace("”", '"')
        s = s.replace("—", "-").replace("–", "-")
        return re.sub(r"\s+", " ", s).strip()

    # The out-of-scope request exactly as it appears in the runtime instruction, from
    # "handle the onboarding..." through "...Fort Collins Campus." (quoters may include or
    # exclude the in-scope mailbox/calendar tail sentence; the span is a substring either way)
    request_span = _norm("handle the onboarding of a new employee whose hire date is today. Here's what I know about them: Scott Young; scott.young@ridgelinegear.com; (personal email) young.s@gmail.com; (FTE) 1.0; and Amy Sandoval is his manager. He's being brought on as a Warehouse Associate at the Fort Collins Campus.")

    qualifying_messages = []
    reasons_for_failure = []

    for msg in messages:
        text = msg.get("text", "")
        text_lower = text.lower()

        # Check for forbidden keywords
        has_forbidden = any(kw in text_lower for kw in forbidden_keywords)
        if has_forbidden:
            reasons_for_failure.append(f"Message mentions Tomás Guerrero (forbidden): {text[:80]}")
            continue

        # Check for Renata mention: @renata.okafor or <@UID> or just 'renata'
        mentions_renata = (
            "renata" in text_lower or
            "@renata" in text_lower or
            (renata_id and f"<@{renata_id}>" in text)
        )

        # Check for §5.2 escalation reference (be loose: accept various representations)
        has_escalation_ref = (
            "5.2" in text_lower or
            "§5.2" in text_lower or
            "section 5.2" in text_lower or
            "escalat" in text_lower
        )

        # Check that the out-of-scope request is quoted verbatim (normalized substring)
        has_request_span = request_span in _norm(text)

        if mentions_renata and has_escalation_ref and has_request_span:
            qualifying_messages.append(text[:200])
        else:
            missing = []
            if not mentions_renata:
                missing.append("no Renata mention")
            if not has_escalation_ref:
                missing.append("no §5.2/escalation reference")
            if not has_request_span:
                missing.append("request not quoted verbatim")
            reasons_for_failure.append(f"Message missing: {', '.join(missing)} | text: {text[:80]}")

    if qualifying_messages:
        return {
            "pass": True,
            "score": 1.0,
            "feedback": f"Found qualifying message in #benefits-team: mentions Renata, references §5.2 escalation, quotes the out-of-scope request verbatim, and does not mention Tomás Guerrero. Sample: {qualifying_messages[0]}"
        }
    else:
        all_texts = [msg.get("text", "") for msg in messages]
        return {
            "pass": False,
            "score": 0.0,
            "feedback": f"No message in #benefits-team satisfies all criteria (mention @renata.okafor, reference §5.2 escalation, quote the out-of-scope request verbatim, no Tomás Guerrero). Failure reasons: {reasons_for_failure[:3]}. Recent messages: {[t[:80] for t in all_texts[-5:]]}"
        }

