from pathlib import Path
import openpyxl

def verify(workspace_path, external_services_path=None):
    # Search for any leave tracker xlsx file with loose matching
    ws_path = Path(workspace_path)
    tracker_files = set()
    for pattern in ["*leave_tracker*", "*Leave_Tracker*", "*leave*tracker*", "*Leave*Tracker*", "*LEAVE*TRACKER*"]:
        tracker_files.update(ws_path.glob(pattern))
    xlsx_files = [f for f in tracker_files if f.suffix.lower() == ".xlsx"]

    if not xlsx_files:
        # Broaden: any xlsx with 'leave' or 'tracker' in name
        all_xlsx = list(ws_path.glob("*.xlsx"))
        if not all_xlsx:
            # Try recursively
            all_xlsx = list(ws_path.rglob("*.xlsx"))
        if not all_xlsx:
            return {"pass": False, "score": 0.0, "feedback": "No .xlsx file found in workspace."}
        leave_files = [f for f in all_xlsx if "leave" in f.name.lower() or "tracker" in f.name.lower()]
        if leave_files:
            xlsx_files = leave_files
        else:
            xlsx_files = all_xlsx

    # Try each candidate file
    for tracker_path in xlsx_files:
        try:
            wb = openpyxl.load_workbook(tracker_path, data_only=True)
            # Try active sheet first, then all sheets
            sheets_to_check = [wb.active] + [wb[s] for s in wb.sheetnames if wb[s] != wb.active]
            for ws in sheets_to_check:
                # Check N11 (row=11, column=14)
                cell_value = ws.cell(row=11, column=14).value
                if cell_value is not None:
                    cell_str = str(cell_value).strip().lower()
                    if "p1" in cell_str:
                        return {"pass": True, "score": 1.0, "feedback": f"Cell N11 in '{tracker_path.name}' (sheet '{ws.title}') contains '{cell_value}' which includes 'P1'."}

            # Also search for LC-2026-0321 row and check its priority column
            for ws in sheets_to_check:
                target_row = None
                priority_col = None
                # Find header row and priority column
                for row in range(1, min(ws.max_row + 1, 5)):
                    for col in range(1, ws.max_column + 1):
                        val = ws.cell(row=row, column=col).value
                        if val and "priority" in str(val).strip().lower():
                            priority_col = col
                            break
                    if priority_col:
                        break
                # Find row with LC-2026-0321
                for row in range(1, ws.max_row + 1):
                    for col in range(1, ws.max_column + 1):
                        val = ws.cell(row=row, column=col).value
                        if val and "lc-2026-0321" in str(val).strip().lower():
                            target_row = row
                            break
                    if target_row:
                        break
                if target_row and priority_col:
                    pval = ws.cell(row=target_row, column=priority_col).value
                    if pval and "p1" in str(pval).strip().lower():
                        return {"pass": True, "score": 1.0, "feedback": f"Row {target_row} for LC-2026-0321 in '{tracker_path.name}' (sheet '{ws.title}') has priority '{pval}' which includes 'P1'."}
            wb.close()
        except Exception as e:
            continue

    # Final failure - try to give useful info
    try:
        tracker_path = xlsx_files[0]
        wb = openpyxl.load_workbook(tracker_path, data_only=True)
        ws = wb.active
        cell_value = ws.cell(row=11, column=14).value
        wb.close()
        return {"pass": False, "score": 0.0, "feedback": f"Cell N11 in '{tracker_path.name}' contains '{cell_value}', expected a value containing 'P1' (case-insensitive). Checked {len(xlsx_files)} file(s)."}
    except Exception as e:
        return {"pass": False, "score": 0.0, "feedback": f"Could not verify. Error: {e}. Checked files: {[f.name for f in xlsx_files]}"}

from pathlib import Path
import json

def verify(workspace_path, external_services_path=None):
    # Check external_services_path for slack_data.json
    slack_path = None
    if external_services_path:
        candidate = Path(external_services_path) / "slack_data.json"
        if candidate.exists():
            slack_path = candidate
    # Also check workspace_path
    if not slack_path:
        candidate = Path(workspace_path) / "slack_data.json"
        if candidate.exists():
            slack_path = candidate

    if not slack_path:
        return {"pass": False, "score": 0.0, "feedback": "slack_data.json not found in workspace or external services path."}

    try:
        with open(slack_path, 'r') as f:
            data = json.load(f)
    except Exception as e:
        return {"pass": False, "score": 0.0, "feedback": f"Failed to read/parse slack_data.json: {e}"}

    # Slack data format per the spec:
    # {
    #   "channels": { "C001": { "id": "C001", "name": "general", ... } },
    #   "messages": { "C001": [ {message}, ... ] }
    # }
    # We need to find the channel ID for #benefits-team, then count messages.

    benefits_channel_id = None
    benefits_messages = None

    # Strategy 1: Use the standard slack_data format (channels dict keyed by ID, messages dict keyed by channel ID)
    if isinstance(data, dict):
        channels = data.get('channels', {})
        messages = data.get('messages', {})

        # Find channel ID for benefits-team
        if isinstance(channels, dict):
            for ch_id, ch_info in channels.items():
                if isinstance(ch_info, dict):
                    ch_name = (ch_info.get('name', '') or '').strip().lower().replace('#', '')
                    if ch_name == 'benefits-team':
                        benefits_channel_id = ch_id
                        break
                elif isinstance(ch_info, str):
                    # Maybe channels is {id: name}
                    if ch_info.strip().lower().replace('#', '') == 'benefits-team':
                        benefits_channel_id = ch_id
                        break

        # If we found the channel ID, get messages by channel ID
        if benefits_channel_id and isinstance(messages, dict):
            channel_msgs = messages.get(benefits_channel_id, [])
            if isinstance(channel_msgs, list):
                benefits_messages = channel_msgs

        # Fallback: Try finding messages keyed directly by channel name
        if benefits_messages is None and isinstance(messages, dict):
            for key in messages:
                normalized = key.strip().lower().replace('#', '')
                if normalized == 'benefits-team':
                    val = messages[key]
                    if isinstance(val, list):
                        benefits_messages = val
                    break

        # Fallback: top-level dict with channel names as keys
        if benefits_messages is None:
            for key in data:
                normalized = key.strip().lower().replace('#', '')
                if normalized == 'benefits-team':
                    channel_data = data[key]
                    if isinstance(channel_data, list):
                        benefits_messages = channel_data
                    elif isinstance(channel_data, dict) and 'messages' in channel_data:
                        benefits_messages = channel_data['messages']
                    break

        # Fallback: channels is a list of dicts
        if benefits_messages is None and isinstance(channels, list):
            for ch in channels:
                if isinstance(ch, dict):
                    ch_name = (ch.get('name', '') or ch.get('channel_name', '') or '').strip().lower().replace('#', '')
                    if ch_name == 'benefits-team':
                        ch_id = ch.get('id', '')
                        if ch_id and isinstance(messages, dict):
                            benefits_messages = messages.get(ch_id, [])
                        elif 'messages' in ch:
                            benefits_messages = ch['messages']
                        break

        # Fallback: messages is a flat list with channel field
        if benefits_messages is None and isinstance(messages, list):
            benefits_messages = []
            for msg in messages:
                if isinstance(msg, dict):
                    ch = (msg.get('channel', '') or msg.get('channel_name', '') or '').strip().lower().replace('#', '')
                    if ch == 'benefits-team':
                        benefits_messages.append(msg)

    if benefits_messages is None:
        debug_info = ""
        if isinstance(data, dict):
            debug_info = f" Top-level keys: {list(data.keys())}."
            channels = data.get('channels', {})
            if isinstance(channels, dict):
                channel_names = []
                for ch_id, ch_info in channels.items():
                    if isinstance(ch_info, dict):
                        channel_names.append(f"{ch_id}={ch_info.get('name', '?')}")
                    else:
                        channel_names.append(f"{ch_id}={ch_info}")
                debug_info += f" Channels: {channel_names}."
            msgs = data.get('messages', {})
            if isinstance(msgs, dict):
                debug_info += f" Message keys: {list(msgs.keys())}."
        return {"pass": False, "score": 0.0, "feedback": f"Could not find #benefits-team channel in slack_data.json.{debug_info}"}

    count = len(benefits_messages)

    if count == 3:
        return {"pass": True, "score": 1.0, "feedback": f"Found exactly 3 messages in #benefits-team channel as expected."}
    else:
        return {"pass": False, "score": 0.0, "feedback": f"Expected 3 messages in #benefits-team channel, but found {count}. Messages: {json.dumps(benefits_messages, default=str)[:1000]}"}

