from pathlib import Path
import json

def verify(workspace_path, external_services_path=None):
    mailbox_path = None

    # Try external_services_path first, then workspace_path
    if external_services_path:
        candidate = Path(external_services_path) / "mailbox.json"
        if candidate.exists():
            mailbox_path = candidate

    if not mailbox_path:
        candidate = Path(workspace_path) / "mailbox.json"
        if candidate.exists():
            mailbox_path = candidate

    if not mailbox_path:
        return {"pass": False, "score": 0.0, "feedback": "No mailbox.json found in either external_services_path or workspace_path."}

    try:
        with open(mailbox_path, "r", encoding="utf-8") as f:
            data = json.load(f)
    except Exception as e:
        return {"pass": False, "score": 0.0, "feedback": f"Failed to read/parse mailbox.json: {e}"}

    emails = data.get("emails", [])
    total_emails = len(emails)
    issues = []
    score = 1.0

    # Build a lookup by email_id (could be int or string)
    emails_by_id = {}
    max_email_id = None
    for email in emails:
        eid = email.get("email_id", email.get("id", None))
        if eid is not None:
            try:
                eid_int = int(eid)
            except (ValueError, TypeError):
                eid_int = None
            if eid_int is not None:
                emails_by_id[eid_int] = email
                if max_email_id is None or eid_int > max_email_id:
                    max_email_id = eid_int

    # Check: no emails after email_id 40
    emails_after_40 = [eid for eid in emails_by_id if eid > 40]
    if emails_after_40:
        issues.append(f"Found emails with email_id > 40: {sorted(emails_after_40)}. There should be no emails after email_id 40.")
        score = 0.0

    # Check: email_id 40 exists and is addressed to tomas.guerrero@ridgelinegear.com
    expected_recipient = "tomas.guerrero@ridgelinegear.com"
    if 40 in emails_by_id:
        email_40 = emails_by_id[40]
        to_addr = email_40.get("to_addr", email_40.get("to", ""))
        # Normalize: accept string or list
        if isinstance(to_addr, str):
            to_addrs = [to_addr.strip().lower()]
        elif isinstance(to_addr, list):
            to_addrs = [a.strip().lower() for a in to_addr]
        else:
            to_addrs = []

        if expected_recipient not in to_addrs:
            issues.append(f"Email with email_id 40 is addressed to '{to_addr}', expected '{expected_recipient}'.")
            score = 0.0
    else:
        issues.append(f"No email with email_id 40 found. Available email_ids: {sorted(emails_by_id.keys())[-10:] if emails_by_id else 'none'}")
        score = 0.0

    if issues:
        return {"pass": False, "score": score, "feedback": "Issues found: " + "; ".join(issues)}
    else:
